    storyConsequence: { correct: { zh: '围栏长度——圆的计算完美！做得漂亮！', en: 'Fence Length — Well done!' }, wrong: { zh: '圆的数字有点偏——检查一下公式里有没有用 π？', en: 'Not quite... Try again!' } },
