    tutorialSteps: [
      { text: { zh: '荀彧：为什么要学分数指数？\n$8^{1/3}$ 看起来很奇怪——指数居然是分数？\n其实它就是"开方"的另一种写法：$8^{1/3} = \\sqrt[3]{8}$。', en: 'Xun Yu: "Why learn fractional indices?\n$8^{1/3}$ looks strange — a fraction as an exponent?\nIt\'s just another way of writing \'root\': $8^{1/3} = \\sqrt[3]{8}$."' }, highlightField: 'ans' },
      { text: { zh: '荀彧：分数指数的含义\n$a^{1/n}$ = $\\sqrt[n]{a}$ = 哪个数乘以自己 $n$ 次等于 $a$？\n这就像反向思考：已知结果，找原因。', en: 'Xun Yu: "What fractional indices mean\n$a^{1/n}$ = $\\sqrt[n]{a}$ = which number multiplied by itself $n$ times gives $a$?\nThink backwards: you know the result, find the cause."' }, highlightField: 'ans' },
      { text: { zh: '荀彧：分析 $8^{1/3}$\n我们要找：$? \\times ? \\times ? = 8$\n（三个相同的数相乘等于 8）', en: 'Xun Yu: "Analyse $8^{1/3}$\nWe need: $? \\times ? \\times ? = 8$\n(three identical numbers multiply to give 8)"' }, highlightField: 'ans' },
      { text: { zh: '荀彧：尝试\n$2 \\times 2 \\times 2 = 8$ ✓\n所以 $8^{1/3} = 2$', en: 'Xun Yu: "Try it\n$2 \\times 2 \\times 2 = 8$ ✓\nSo $8^{1/3} = 2$"' }, highlightField: 'ans' },
      { text: { zh: '荀彧：答案\n$8^{1/3} = 2$', en: 'Xun Yu: "Answer\n$8^{1/3} = 2$"' }, highlightField: 'ans' },
      { text: { zh: '荀彧：验算\n$2^3 = 2 \\times 2 \\times 2 = 8$ ✓\n开方和乘方是互逆运算！', en: 'Xun Yu: "Verify\n$2^3 = 2 \\times 2 \\times 2 = 8$ ✓\nRoots and powers are inverse operations!"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '分数指数就是开方：$a^{1/n} = \\sqrt[n]{a}$。', en: 'Fractional index means root: $a^{1/n} = \\sqrt[n]{a}$.' }, formula: '$a^{1/n} = \\sqrt[n]{a}$', tips: [{ zh: '荀彧提示：开方是乘方的逆运算——知道结果反推原因！', en: 'Xun Yu Tip: Root is the inverse of power — work backwards from the result!' }] },
    storyConsequence: { correct: { zh: '分兵成功——分数指数不过如此！你的代数直觉越来越敏锐了。', en: 'Division successful — fractional indices conquered! Your algebraic intuition grows sharper.' }, wrong: { zh: '分兵出了差错——想想哪个数乘以自己3次等于8？', en: 'Division went wrong — think: what number times itself 3 times equals 8?' } },
