    tutorialSteps: [
      { text: { zh: '郭嘉：为什么要学幂的幂？\n当你把一个指数表达式再次乘方时——比如"翻倍的部队再翻倍"——指数法则帮你一步化简。\n$(ax^m)^n$：外面的指数要分配给里面的每一部分！', en: 'Guo Jia: "Why learn power of a power?\nWhen you raise an index expression to another power — like \'doubling a doubled force\' — index laws simplify it in one step.\n$(ax^m)^n$: the outer exponent distributes to every part inside!"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：幂的幂法则\n$(ax^m)^n = a^n \\times x^{m \\times n}$\n系数 $a$ 也要乘方！指数要相乘！', en: 'Guo Jia: "Power of a power rule\n$(ax^m)^n = a^n \\times x^{m \\times n}$\nThe coefficient $a$ is also raised! Exponents multiply!"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：代入\n$(2x^3)^2$\n系数部分：$2^2 = ?$\n指数部分：$3 \\times 2 = ?$', en: 'Guo Jia: "Substitute\n$(2x^3)^2$\nCoefficient: $2^2 = ?$\nExponent: $3 \\times 2 = ?$"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：计算\n$2^2 = 4$\n$3 \\times 2 = 6$\n$(2x^3)^2 = 4x^6$', en: 'Guo Jia: "Calculate\n$2^2 = 4$\n$3 \\times 2 = 6$\n$(2x^3)^2 = 4x^6$"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：答案\n$a = 4$', en: 'Guo Jia: "Answer\n$a = 4$"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：验算\n$(2x^3)^2 = (2x^3)(2x^3) = 4x^6$ ✓\n展开确认和法则结果一致！', en: 'Guo Jia: "Verify\n$(2x^3)^2 = (2x^3)(2x^3) = 4x^6$ ✓\nExpanding confirms the rule!"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '幂的幂：外层指数分配给系数和内层指数。', en: 'Power of a power: outer exponent distributes to coefficient and inner exponent.' }, formula: '$(ax^m)^n = a^n x^{mn}$', tips: [{ zh: '郭嘉提示：外面的指数是"放大器"——系数和指数都要受它影响！', en: 'Guo Jia Tip: The outer exponent is an amplifier — both coefficient and exponent are affected!' }] },
    storyConsequence: { correct: { zh: '翻倍合幂——法则运用精准！曹操的代数军团越来越强大了！', en: 'Double & merge — precise application! Cao Cao\'s algebra army grows ever stronger!' }, wrong: { zh: '合幂的时候系数忘了乘方——$2^2 = 4$，别忘了系数也要算！', en: 'Forgot to raise the coefficient — $2^2 = 4$, don\'t forget the coefficient too!' } },
