    tutorialSteps: [
      { text: { zh: '荀彧：为什么要认识平行四边形？\n平行四边形是四边形家族的核心——长方形、菱形、正方形都是它的特例！\n认识它，就等于认识了一大类图形。', en: 'Xun Yu: "Why learn about parallelograms?\nParallelograms are the core of the quadrilateral family — rectangles, rhombi, squares are all special cases!\nKnow it, and you know a whole family of shapes."' }, highlightField: 'ans' },
      { text: { zh: '荀彧：平行四边形的定义\n两组对边分别平行的四边形。\n"平行"= 两条线永远不相交，"四边形"= 四条边。', en: 'Xun Yu: "Parallelogram definition\nA quadrilateral with two pairs of parallel sides.\n\'Parallel\' = lines never meet, \'quadrilateral\' = four sides."' }, highlightField: 'ans' },
      { text: { zh: '荀彧：数边\n上边、下边、左边、右边——共 4 条。\n而且对边平行且等长！', en: 'Xun Yu: "Count the sides\nTop, bottom, left, right — 4 sides total.\nOpposite sides are parallel AND equal!"' }, highlightField: 'ans' },
      { text: { zh: '荀彧：关键属性\n对边平行 + 对边等长 + 对角相等。\n这三条就是平行四边形的身份证。', en: 'Xun Yu: "Key properties\nOpposite sides parallel + opposite sides equal + opposite angles equal.\nThese three form the parallelogram\'s ID."' }, highlightField: 'ans' },
      { text: { zh: '荀彧：答案\n平行四边形有 $4$ 条边。', en: 'Xun Yu: "Answer\nA parallelogram has $4$ sides."' }, highlightField: 'ans' },
      { text: { zh: '荀彧：验算\n四边形内角和 = $360°$。平行四边形对角相等：$\\alpha + \\beta = 180°$。\n4 条边、4 个角、内角和 $360°$ ✓', en: 'Xun Yu: "Verify\nQuadrilateral angle sum = $360°$. Parallelogram has equal opposite angles: $\\alpha + \\beta = 180°$.\n4 sides, 4 angles, angle sum $360°$ ✓"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '平行四边形有 4 条边，对边平行且等长，对角相等。', en: 'A parallelogram has 4 sides, opposite sides parallel and equal, opposite angles equal.' }, formula: '$n = 4$', tips: [{ zh: '荀彧提示：对边平行 + 等长 = 平行四边形！', en: 'Xun Yu Tip: Opposite sides parallel + equal = parallelogram!' }] },
    storyConsequence: { correct: { zh: '阵形辨别——平行四边形识别准确！', en: 'Formation Properties — parallelogram identified correctly!' }, wrong: { zh: '平行四边形是四边形——数一数：上、下、左、右 = 4 条边。', en: 'A parallelogram is a quadrilateral — count: top, bottom, left, right = 4 sides.' } },
