    tutorialSteps: [
      { text: { zh: '郭嘉：为什么要学尺规作图？\n古代营寨设计只有尺和圆规——没有量角器！\n但只用这两样工具，就能精确作出等边三角形。这是几何之美。', en: 'Guo Jia: "Why learn ruler-compass construction?\nAncient fortress design had only a ruler and compass — no protractor!\nBut with just these two tools, you can precisely construct an equilateral triangle. That\'s the beauty of geometry."' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：等边三角形的秘密\n三条边相等 → 三个角也相等。\n三角形内角和 = $180°$，所以每个角 = $180° \\div 3$。', en: 'Guo Jia: "The equilateral triangle secret\nThree equal sides → three equal angles.\nAngle sum = $180°$, so each angle = $180° \\div 3$."' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：计算\n$180° \\div 3 = 60°$', en: 'Guo Jia: "Calculate\n$180° \\div 3 = 60°$"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：尺规作图步骤\n1. 画一条底边 AB\n2. 以 A 为圆心、AB 为半径画弧\n3. 以 B 为圆心、同半径画弧\n4. 两弧交于 C → 连接 AC、BC', en: 'Guo Jia: "Construction steps\n1. Draw base AB\n2. Arc centred at A, radius AB\n3. Arc centred at B, same radius\n4. Arcs meet at C → join AC, BC"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：答案\n每个角 = $60°$。三面均衡，固若金汤！', en: 'Guo Jia: "Answer\nEach angle = $60°$. Three equal sides, impenetrable!"' }, highlightField: 'ans' },
      { text: { zh: '郭嘉：验算\n$60° \\times 3 = 180°$ ✓ 内角和正确！\n三条边等长 → 三个角等大 → $60°$ 是唯一解。✓', en: 'Guo Jia: "Verify\n$60° \\times 3 = 180°$ ✓ Angle sum correct!\nThree equal sides → three equal angles → $60°$ is the only solution. ✓"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '等边三角形每个角 = 60°，可用尺规精确作图。', en: 'Each angle of an equilateral triangle = 60°, constructible by ruler and compass.' }, formula: '$\\frac{180°}{3} = 60°$', tips: [{ zh: '郭嘉提示：等边 = 等角 = 60°！', en: 'Guo Jia Tip: Equal sides = equal angles = 60°!' }] },
    storyConsequence: { correct: { zh: '尺规营寨——60° 完美等边！', en: 'Compass Fortress — 60° perfect equilateral!' }, wrong: { zh: '等边三角形三个角相等，180° ÷ 3 = ?', en: 'Equilateral triangle has three equal angles, 180° ÷ 3 = ?' } },
