    difficulty: 'Medium', reward: 160, kpId: 'kp-4.2-04', sectionId: 'geometry',
    tutorialSteps: [
      { text: { zh: '关羽：为什么要学轨迹？\n巡逻路线不是随便走的——到两个哨塔保持等距，才能均衡防守。\n"满足某个条件的所有点"的集合，叫轨迹。', en: 'Guan Yu: "Why learn loci?\nPatrol routes aren\'t random — staying equidistant from two watchtowers gives balanced defense.\nThe set of ALL points satisfying a condition is called a locus."' }, highlightField: 'ans' },
      { text: { zh: '关羽：等距轨迹\n到 A 的距离 = 到 B 的距离。\n想象 A 和 B 是两个哨塔，中间那条"公平线"在哪？', en: 'Guan Yu: "Equidistant locus\nDistance to A = distance to B.\nImagine A and B are two watchtowers. Where is the \'fair line\' in between?"' }, highlightField: 'ans' },
      { text: { zh: '关羽：垂直平分线\n到两点等距的轨迹是它们连线的垂直平分线——一条直线！\n不是圆（圆是到一个点等距的轨迹）。', en: 'Guan Yu: "Perpendicular bisector\nThe locus equidistant from two points is the perpendicular bisector — a straight line!\nNot a circle (a circle is equidistant from ONE point)."' }, highlightField: 'ans' },
      { text: { zh: '关羽：区分两种轨迹\n到一个点等距 → 圆\n到两个点等距 → 直线（垂直平分线）', en: 'Guan Yu: "Distinguish two loci\nEquidistant from ONE point → circle\nEquidistant from TWO points → straight line (perpendicular bisector)"' }, highlightField: 'ans' },
      { text: { zh: '关羽：答案\n到两定点等距的轨迹是直线（选 $2$）。', en: 'Guan Yu: "Answer\nLocus equidistant from two points is a straight line (choose $2$)."' }, highlightField: 'ans' },
      { text: { zh: '关羽：验算\n取垂直平分线上任意一点 P，用勾股定理验证 PA = PB ✓\n取线外一点 Q，QA ≠ QB ✓ 只有线上的点才等距！', en: 'Guan Yu: "Verify\nTake any point P on the perpendicular bisector. Use Pythagoras to verify PA = PB ✓\nTake a point Q off the line. QA ≠ QB ✓ Only points on the line are equidistant!"' }, highlightField: 'ans' },
    ],
    secret: { concept: { zh: '到两定点等距的轨迹是连线的垂直平分线（一条直线）。', en: 'Locus equidistant from two fixed points is the perpendicular bisector (a straight line).' }, formula: '$PA = PB$', tips: [{ zh: '关羽提示：一个点→圆，两个点→直线！', en: 'Guan Yu Tip: One point → circle, two points → straight line!' }] },
